# ==================== CNCL-6: `5dive council` (v0.11) ====================
# Standalone deliberation council. The engine + CLI are node modules (src/council/
# engine.mjs + cli.mjs); this bundle ships as ONE bash file, so they are embedded
# below and materialized to a temp dir at call time — the same self-contained
# pattern as `memory search`. This file is GENERATED by src/council/gen_cmd.mjs
# from those two canonical sources; edit the .mjs (or the template) and re-run the
# generator, never this embedded copy. Drift is caught by tests/council_cli_contract.mjs.
#
# Ports the four tested prototypes (convene/verdict, gate-clear map, loop+node,
# standing benches + tamper-evident receipt). Model calls go through the A-with-seam
# adapter (COUNCIL_API_KEY / COUNCIL_BASE_URL); COUNCIL_MOCK=1 runs offline.

COUNCIL_DIR="${STATE_DIR}/council"
COUNCIL_REGISTRY="${COUNCIL_DIR}/benches.json"
COUNCIL_RECEIPTS="${COUNCIL_DIR}/receipts"

_council_help() {
  cat >&2 <<'COUNCIL_HELP'
5dive council — standalone deliberation council (v0.11)

  5dive council convene "<question>" [--seats=a,b,c] [--mode=quick|deliberate|adversarial]
                                     [--bench=<name>] [--class=<decisionClass>]
                                     [--threshold=<n>] [--veto-by=<who> --veto-reason=<why>]
                                     [--timeout=120] [--idle-secs=5] [--poll-secs=2] [--standalone]
      Convene a council over a question. By DEFAULT (CNCL-7) it DISPATCHES the question
      to the real seated agents — each seat votes via its OWN harness over the
      `5dive agent ask` rail, no shared model key. A seat that times out or replies
      without a COUNCIL-VOTE line is a recorded ABSTAIN; a convene that falls below
      quorum returns no verdict and auto-escalates with a human brief. The first round
      is BLIND (no seat sees another before its own vote); adversarial adds a rebuttal
      round, recorded separately. Emits an auditable verdict (deterministic tally over
      the current roster + founder veto) and a tamper-evident, root-signed receipt.
      Defaults to the 5-seat standing Council. --standalone selects the deferred
      single-key modelCall seam instead of dispatch.

  5dive council bench ls
  5dive council bench show <name>
  5dive council bench add  <name> --seats=a:lens|b:lens [--mode=] [--threshold=] [--desc=]
  5dive council bench rm   <name>
      Manage the persisted, editable registry of standing benches (built-ins:
      council, ship, brand, security — fail-closed on an unknown name; add/rm are
      privileged governance writes and need sudo).

  Add --json for a machine envelope. The default dispatch path needs NO model key
  (each seat uses its own harness). The --standalone seam uses COUNCIL_API_KEY
  (A-with-seam; BYO/OpenRouter via COUNCIL_BASE_URL). COUNCIL_MOCK=1 runs a
  deterministic offline council (no key, no network, no agent dispatch) for tests + smoke.
COUNCIL_HELP
}

_council_write_runtime() {
  local dir="$1"
  cat > "$dir/engine.mjs" <<'COUNCIL_ENGINE_MJS'
__ENGINE_MJS__
COUNCIL_ENGINE_MJS
  cat > "$dir/cli.mjs" <<'COUNCIL_CLI_MJS'
__CLI_MJS__
COUNCIL_CLI_MJS
}

cmd_council() {
  command -v node >/dev/null 2>&1 || fail "$E_GENERIC" "5dive council needs node on PATH"
  command -v jq   >/dev/null 2>&1 || fail "$E_GENERIC" "5dive council needs jq on PATH"
  local sub="${1:-}"; [[ $# -gt 0 ]] && shift || true
  case "$sub" in
    ""|-h|--help|help) _council_help; return 0 ;;
    convene|bench) ;;
    *) fail "$E_USAGE" "unknown council command: $sub (convene|bench)" ;;
  esac

  local dir; dir="$(mktemp -d -t 5dive-council.XXXXXX)" || fail "$E_GENERIC" "mktemp failed"
  # shellcheck disable=SC2064
  trap "rm -rf '$dir'" RETURN
  _council_write_runtime "$dir"

  if [[ "$sub" == "bench" ]]; then
    local action="${1:-ls}"
    case "$action" in
      add|rm)
        mkdir -p "$COUNCIL_DIR" 2>/dev/null || true
        if [[ ! -w "$COUNCIL_DIR" ]]; then
          fail "$E_PERMISSION" "editing standing benches writes ${COUNCIL_REGISTRY} (root-owned) — re-run via: sudo 5dive council bench $action $*"
        fi
        ;;
    esac
    # cli.mjs always emits JSON; format it here so text/JSON honor the global contract.
    local braw; braw="$(node "$dir/cli.mjs" bench "$@" --registry="$COUNCIL_REGISTRY")" || return $?
    if (( JSON_MODE )); then
      printf '%s' "$braw" | jq '{ok:true, data: .}'
    elif [[ "$action" == "ls" ]]; then
      printf '%s' "$braw" | jq -r '.benches[] | "  \(.name)\t\(if .builtin then "(built-in)" else "" end)\(if .custom then "(custom)" else "" end)"'
    elif [[ "$action" == "show" ]]; then
      printf '%s' "$braw" | jq -r '"bench:  \(.name)\ndesc:   \(.description)\nmode:   \(.mode)\nseats:  \(.seats | map(.id) | join(", "))"'
    else
      printf '%s' "$braw" | jq -r 'to_entries[0] | "OK — bench \(.value) \(.key)"'
    fi
    return 0
  fi

  # convene ------------------------------------------------------------------
  local stamped; stamped="$(date -u +%Y-%m-%dT%H:%M:%SZ)"
  local raw
  raw="$(node "$dir/cli.mjs" convene "$@" --registry="$COUNCIL_REGISTRY" --stamped-at="$stamped")" || return $?

  # Seal the receipt canonical at the root HMAC rail — a standalone engine has no
  # key, so the seal (via gate-proof) is what makes the verdict tamper-evident. The
  # founder veto + dissent already ride INSIDE the signed bytes (canonicalTranscript).
  local canonical digest=""
  canonical="$(printf '%s' "$raw" | jq -r '.receipt.canonical // empty')"
  if [[ -n "$canonical" ]]; then
    if [[ "$(id -u)" -eq 0 ]]; then
      digest="$(printf '%s' "$canonical" | cmd_gate_proof_sign_stdin)" || digest=""
    else
      digest="$(printf '%s' "$canonical" | sudo -n 5dive gate-proof sign 2>/dev/null)" || digest=""
    fi
    if [[ -n "$digest" ]]; then
      mkdir -p "$COUNCIL_RECEIPTS" 2>/dev/null || true
      if [[ -w "$COUNCIL_RECEIPTS" ]]; then
        printf '%s' "$raw" | jq --arg d "$digest" --arg s "$stamped" \
          '{stampedAt:$s, sealedDigest:$d, council, question, disposition, verdict, canonical: .receipt.canonical}' \
          > "${COUNCIL_RECEIPTS}/${stamped//:/-}.json" 2>/dev/null || true
      fi
    fi
  fi

  if (( JSON_MODE )); then
    printf '%s' "$raw" | jq --arg d "$digest" '{ok:true, data: (. + {sealedDigest: $d})}'
  else
    local council q disp rec tally conf dissent brief
    council="$(printf '%s' "$raw" | jq -r '.council')"
    q="$(printf '%s' "$raw" | jq -r '.question')"
    disp="$(printf '%s' "$raw" | jq -r '.disposition')"
    rec="$(printf '%s' "$raw" | jq -r '.verdict.recommendation')"
    tally="$(printf '%s' "$raw" | jq -r '.verdict.tally | "a\(.approve)/r\(.reject)/e\(.escalate)"')"
    conf="$(printf '%s' "$raw" | jq -r '.verdict.confidence')"
    dissent="$(printf '%s' "$raw" | jq -r '.verdict.dissent // "none"')"
    brief="$(printf '%s' "$raw" | jq -r '.verdict.brief // empty')"
    echo "council:      $council"
    echo "question:     $q"
    echo "disposition:  $disp  (recommendation=$rec, tally=$tally, confidence=$conf)"
    [[ -n "$dissent" && "$dissent" != "none" ]] && echo "dissent:      $dissent"
    [[ -n "$brief" ]] && echo "brief:        $brief"
    if [[ -n "$digest" ]]; then
      echo "receipt:      sealed (${digest:0:16}…)"
    else
      echo "receipt:      unsealed (no gate-proof key / not root — run via sudo to seal)"
    fi
  fi
}

# In-process root seal: reuse the existing gate-proof signer without a re-exec when
# we are already root (keeps the HMAC key handling in one place).
cmd_gate_proof_sign_stdin() { cmd_gate_proof sign; }
